 18	
 19	import { tickLabels } from '../ChartLabels/styleOverrides';
 20	import ComponentReady from '../ComponentReady/ComponentReady';
 21	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 22	import { getUtilizationQueries } from '../utils/queries';
 23	import { MILLISECONDS_MULTIPLIER, queriesToLink, tickFormat, TICKS_COUNT } from '../utils/utils';
 24	
 25	type NetworkThresholdChartProps = {
 26	  vmi: V1VirtualMachineInstance;
 27	};
 28	
 29	const NetworkThresholdChart: React.FC<NetworkThresholdChartProps> = ({ vmi }) => {
 30	  const { currentTime, duration, timespan } = useDuration();
 31	  const queries = React.useMemo(
 32	    () => getUtilizationQueries({ duration, obj: vmi }),
 33	    [vmi, duration],
 34	  );
 35	  const { height, ref, width } = useResponsiveCharts();
 36	
 37	  const [networkIn] = usePrometheusPoll({
 38	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 39	    endTime: currentTime,
 40	    namespace: vmi?.metadata?.namespace,
 41	    query: queries?.NETWORK_IN_USAGE,
 42	    timespan,
 43	  });
 44	
 45	  const [networkOut] = usePrometheusPoll({
 46	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 47	    endTime: currentTime,
 48	    namespace: vmi?.metadata?.namespace,
 49	    query: queries?.NETWORK_OUT_USAGE,
 50	    timespan,
 51	  });
 52	
 53	  const networkInData = networkIn?.data?.result?.[0]?.values;
 54	  const networkOutData = networkOut?.data?.result?.[0]?.values;
 55	  const chartDataIn = networkInData?.map(([x, y]) => {
 56	    return { name: 'Network In', x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 57	  });
 58	
 59	  const chartDataOut = networkOutData?.map(([x, y]) => {
 60	    return { name: 'Network Out', x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 61	  });
 62	
 63	  const isReady = !isEmpty(chartDataOut) || !isEmpty(chartDataIn);
 64	
 65	  return (
 66	    <ComponentReady isReady={isReady}>
 67	      <div className="util-threshold-chart" ref={ref}>
 68	        <Link to={queriesToLink([queries?.NETWORK_IN_USAGE, queries?.NETWORK_OUT_USAGE])}>
 69	          <Chart
 70	            containerComponent={
 71	              <ChartVoronoiContainer
 72	                labels={({ datum }) => {
 73	                  return `${datum?.name}: ${xbytes(datum?.y, { fixed: 2, iec: true })}`;
 74	                }}
 75	                constrainToVisibleArea
 76	              />
 77	            }
 78	            domain={{
 79	              x: [currentTime - timespan, currentTime],
 80	            }}
 81	            height={height}
 82	            padding={35}
 83	            scale={{ x: 'time', y: 'linear' }}
 84	            width={width}
 85	          >
 86	            <ChartAxis
 87	              style={{
 88	                tickLabels: { padding: 2, ...tickLabels },
 89	                ticks: { stroke: 'transparent' },
 90	              }}
 91	              axisComponent={<></>}
 92	              tickCount={TICKS_COUNT}
 93	              tickFormat={tickFormat(duration, currentTime)}
 94	            />
 95	            <ChartGroup>
 96	              <ChartArea
 97	                style={{
 98	                  data: {
 99	                    stroke: chart_color_blue_300.value,
100	                  },
101	                }}
102	                data={chartDataOut}
103	              />
104	              <ChartArea
105	                style={{
106	                  data: {
107	                    stroke: chart_color_blue_400.value,
108	                  },
109	                }}
110	                data={chartDataIn}
111	              />
112	            </ChartGroup>
113	          </Chart>
114	        </Link>
115	      </div>
116	    </ComponentReady>
117	  );
118	};
119	
120	export default NetworkThresholdChart;

